-- Migración 014: Tabla plana para la página What to Expect (pageId=what-to-expect).
-- 2 filas: locale 'en' y 'es'. API content.php GET/PUT pageId=what-to-expect.
--
-- El front (WhatToExpectContentFromApi) espera content.hero.title, content.hero.subtitle,
-- content.intro.text, content.sections[] (id, title, icon, content.intro, content.items, content.paragraphs),
-- content.ctaSection.title, content.ctaSection.subtitle, content.ctaSection.ctas[].
-- sections_json y cta_section_json guardan la estructura por idioma; la API combina en/es al responder.
--
-- meta.lastUpdated: siempre rellenar o usar date('c') en GET para evitar ZodError (ver §2.5 PATRON-CONTENIDO-DESDE-BD).
--
-- Dónde ejecutar: mismo servidor/BD que public/api/content.php (phpMyAdmin o línea de comandos).

CREATE TABLE IF NOT EXISTS page_what_to_expect (
  id INT AUTO_INCREMENT PRIMARY KEY,
  locale VARCHAR(5) NOT NULL UNIQUE COMMENT 'en or es',
  meta_last_updated VARCHAR(32),
  meta_version INT DEFAULT 1,
  seo_title VARCHAR(255) DEFAULT '',
  seo_description TEXT,
  hero_title VARCHAR(255) NOT NULL DEFAULT 'What to Expect',
  hero_subtitle VARCHAR(500) DEFAULT '',
  intro_text TEXT,
  sections_json LONGTEXT NOT NULL COMMENT 'JSON array: [{ id, title, icon, content: { intro?, items?: [{ title?, description }], paragraphs? } }] - strings for this locale',
  cta_section_json LONGTEXT NOT NULL COMMENT 'JSON: { title?, subtitle?, ctas: [{ id, title, description?, link, variant? }] } - strings for this locale',
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Datos reales desde export page_content (what-to-expect). Generado con extract-what-to-expect-json.js
INSERT INTO page_what_to_expect (locale, meta_last_updated, meta_version, seo_title, seo_description, hero_title, hero_subtitle, intro_text, sections_json, cta_section_json) VALUES
('en', '2024-01-15T10:00:00Z', 2, 'What to Expect - WholeSelf Counseling', 'Learn what to expect during your therapy journey. From your first session to ongoing therapy, we guide you through every step.', 'What to Expect', 'Your journey to wellness', 'Starting therapy can feel overwhelming. We''re here to guide you through every step of the process, from scheduling your first session to understanding what ongoing therapy looks like. This page addresses common questions and concerns to help you feel prepared and confident.', '[{"id":"before-first-session","title":"Before Your First Session","icon":"CalendarIcon","content":{"intro":"Preparing for your first therapy session is an important step. Here''s what you need to know to feel ready and comfortable.","items":[{"title":"How to Schedule","description":"You can schedule your first session by calling our office or filling out our contact form. We''ll work with you to find a time that fits your schedule."},{"title":"System Setup","description":"Complete your consent paperwork and upload your insurance documents before the first session. Complete your paperwork through ''Session Health'' once you''ve been scheduled."},{"title":"What to Expect Emotionally","description":"It''s completely normal to feel nervous, anxious, or uncertain before your first session. Many people experience these feelings—you''re not alone. Remember that therapy is a safe space, and your therapist is there to support you."},{"title":"How to Prepare","description":"Take some time to think about what you''d like to work on or discuss. You don''t need to have everything figured out—just come as you are. Consider writing down any questions you have or topics you''d like to explore."},{"title":"Virtual Session Preparation","description":"If you''re having a virtual session, make sure you have a quiet, private space with good internet connection. Test your camera and microphone beforehand, and have a backup plan in case of technical issues."}],"paragraphs":[]}},{"id":"first-session","title":"Your First Session","icon":"ChatBubbleLeftRightIcon","content":{"intro":"Your first session is an opportunity for you and your therapist to get to know each other and begin building a therapeutic relationship. Here''s what typically happens.","items":[{"title":"What Happens","description":"The first session typically includes an intake process where your therapist will ask about your background, current concerns, and goals for therapy. This helps them understand your unique situation and how best to support you."},{"title":"How Long It Lasts","description":"Most first sessions last between 50-60 minutes. This gives you and your therapist enough time to discuss your needs and begin establishing a connection."},{"title":"Questions You Might Be Asked","description":"Your therapist may ask about your mental health history, current symptoms, relationships, work, and what brings you to therapy. Remember, you can share as much or as little as you feel comfortable with."},{"title":"Questions You Can Ask","description":"Feel free to ask your therapist about their approach, experience, what therapy will look like, or anything else that''s on your mind. Your questions are welcome and important."},{"title":"Confidentiality Discussion","description":"Your therapist will explain confidentiality and its limits, including when they might need to break confidentiality for safety reasons. This is an important part of establishing trust and safety."},{"title":"Goal Setting","description":"You and your therapist will begin discussing your goals for therapy. These goals can evolve over time, and it''s okay if you''re not sure what you want to work on yet."},{"title":"Paperwork and Consent Forms","description":"You''ll complete necessary paperwork, including consent forms and intake questionnaires. These forms help ensure you understand your rights and the therapeutic process."}],"paragraphs":[]}},{"id":"ongoing-sessions","title":"Ongoing Therapy Sessions","icon":"ClockIcon","content":{"intro":"As you continue in therapy, you''ll develop a rhythm and routine with your therapist. Here''s what ongoing sessions typically look like.","items":[{"title":"Typical Session Structure","description":"Sessions usually begin with a check-in about how you''ve been since the last session. You''ll then explore topics, work through challenges, and develop insights together. Sessions end with a summary and plan for the time between sessions."},{"title":"What Therapy Looks Like","description":"Therapy is primarily a conversation, but it may also include activities, exercises, or homework assignments. Your therapist will tailor the approach to your needs and preferences."},{"title":"Frequency of Sessions","description":"Most people attend therapy weekly, especially in the beginning. As you progress, you might move to bi-weekly or monthly sessions. The frequency depends on your needs and goals."},{"title":"Session Length","description":"Standard therapy sessions are 50-60 minutes long. Some specialized therapies or assessments may have different durations, which will be discussed with you beforehand."},{"title":"What to Expect Over Time","description":"Therapy is a process. You may notice changes gradually, and some sessions may feel more productive than others. Progress isn''t always linear, and that''s normal. Trust the process and be patient with yourself."},{"title":"How Progress is Measured","description":"Progress is measured through ongoing conversations, goal tracking, and your own sense of improvement. You and your therapist will regularly check in about how things are going and adjust as needed."},{"title":"Communication Between Sessions","description":"Your therapist will let you know their policy on communication between sessions. This may include email, phone calls, or messaging platforms. Emergency situations are always handled differently."}],"paragraphs":[]}},{"id":"confidentiality","title":"Confidentiality and Privacy","icon":"LockClosedIcon","content":{"intro":"Your privacy and confidentiality are fundamental to the therapeutic relationship. Here''s what you need to know about how we protect your information.","items":[{"title":"What is Confidential","description":"Everything you share in therapy is confidential. This includes your conversations, records, and any information about your mental health. Your therapist cannot share this information without your written consent, except in specific circumstances."},{"title":"Limits to Confidentiality","description":"There are legal and ethical limits to confidentiality. Your therapist must break confidentiality if there''s a risk of harm to yourself or others, suspected child or elder abuse, or if required by a court order. These situations will be discussed with you when possible."},{"title":"HIPAA Information","description":"We comply with HIPAA (Health Insurance Portability and Accountability Act) regulations, which protect your health information. You have rights regarding your health records, including the right to access and request amendments."},{"title":"Record Keeping","description":"Your therapist maintains confidential records of your sessions as required by law and professional standards. These records are stored securely and are only accessible to authorized personnel."},{"title":"Virtual Session Privacy and Security","description":"Virtual sessions use secure, encrypted platforms that comply with HIPAA requirements. We recommend using a private space and secure internet connection. Your therapist will discuss privacy considerations with you."}],"paragraphs":[]}},{"id":"timeline-expectations","title":"Timeline Expectations","icon":"ChartBarIcon","content":{"intro":"Every person''s therapeutic journey is unique, and there''s no one-size-fits-all timeline. Here''s what to keep in mind about the duration and progress of therapy.","items":[{"title":"How Long Therapy Might Take","description":"The duration of therapy varies greatly depending on your goals, the issues you''re working on, and your individual needs. Some people benefit from short-term therapy (8-12 sessions), while others engage in longer-term therapy. There''s no right or wrong timeline."},{"title":"When to Expect Changes","description":"Some people notice improvements within a few sessions, while for others, change happens more gradually. Early sessions often focus on building trust and understanding your situation. Be patient with yourself and the process."},{"title":"Commitment and Consistency","description":"Regular attendance and active participation are important for progress. However, life happens, and occasional missed sessions are understandable. Communicate with your therapist about any challenges you''re facing with attendance."},{"title":"Ending Therapy","description":"Therapy can end for various reasons: you''ve met your goals, you feel ready to continue independently, or circumstances change. It''s important to have a termination session to process the ending and discuss next steps. You can always return to therapy in the future if needed."}],"paragraphs":[]}},{"id":"virtual-vs-inperson","title":"Virtual vs. In-Person Options","icon":"ComputerDesktopIcon","content":{"intro":"We offer both virtual and in-person therapy options. Both formats are effective, and the best choice depends on your preferences, needs, and circumstances.","items":[{"title":"Differences and Similarities","description":"Both virtual and in-person therapy provide the same quality of care and therapeutic relationship. Virtual therapy offers convenience and accessibility, while in-person therapy provides a dedicated physical space. The therapeutic process and effectiveness are similar in both formats."},{"title":"How to Choose","description":"Consider factors like your comfort level, privacy needs, transportation, schedule flexibility, and personal preference. Some people prefer one format over the other, while others find value in using both. You can discuss options with your therapist."},{"title":"Switching Between Formats","description":"You can switch between virtual and in-person sessions based on your needs. For example, you might prefer in-person sessions but use virtual sessions when traveling or during inclement weather. Discuss your preferences with your therapist."}],"paragraphs":[]}}]', '{"title":"Ready to Begin Your Journey?","subtitle":"Take the first step toward wellness. We''re here to support you every step of the way.","ctas":[{"id":"schedule-session","title":"Schedule Your First Session","description":"Book an appointment that works for your schedule","link":"/contact/i-need-help","variant":"primary"},{"id":"learn-more","title":"Learn More About Our Services","description":"Explore our therapeutic approaches and specializations","link":"/services","variant":"secondary"}]}'),
('es', '2024-01-15T10:00:00Z', 2, 'Que Esperar - WholeSelf Counseling', 'Aprende que esperar durante tu viaje terapeutico. Desde tu primera sesion hasta la terapia continua, te guiamos en cada paso.', 'Que Esperar', 'Tu viaje hacia el bienestar', 'Comenzar la terapia puede sentirse abrumador. Estamos aqui para guiarte en cada paso del proceso, desde programar tu primera sesion hasta entender como se ve la terapia continua. Esta pagina aborda preguntas y preocupaciones comunes para ayudarte a sentirte preparado y confiado.', '[{"id":"before-first-session","title":"Antes de tu Primera Sesion","icon":"CalendarIcon","content":{"intro":"Prepararse para tu primera sesion de terapia es un paso importante. Esto es lo que necesitas saber para sentirte listo y comodo.","items":[{"title":"Como Programar","description":"Puedes programar tu primera sesion llamando a nuestra oficina o completando nuestro formulario de contacto. Trabajaremos contigo para encontrar un horario que se ajuste a tu agenda."},{"title":"Configuracion del Sistema","description":"Completa tu papeleria de consentimiento y sube tus documentos de seguro antes de la primera sesion. Completa tu papeleria a traves de ''Session Health'' una vez que hayas sido programado."},{"title":"Que Esperar Emocionalmente","description":"Es completamente normal sentirse nervioso, ansioso o inseguro antes de tu primera sesion. Muchas personas experimentan estos sentimientos—no estas solo. Recuerda que la terapia es un espacio seguro, y tu terapeuta esta ahi para apoyarte."},{"title":"Como Prepararse","description":"Tomate un tiempo para pensar en que te gustaria trabajar o discutir. No necesitas tener todo resuelto—solo ven como eres. Considera escribir cualquier pregunta que tengas o temas que te gustaria explorar."},{"title":"Preparacion para Sesion Virtual","description":"Si tienes una sesion virtual, asegurate de tener un espacio tranquilo y privado con buena conexion a internet. Prueba tu camara y microfono con anticipacion, y ten un plan de respaldo en caso de problemas tecnicos."}],"paragraphs":[]}},{"id":"first-session","title":"Tu Primera Sesion","icon":"ChatBubbleLeftRightIcon","content":{"intro":"Tu primera sesion es una oportunidad para que tu y tu terapeuta se conozcan y comiencen a construir una relacion terapeutica. Esto es lo que tipicamente sucede.","items":[{"title":"Que Sucede","description":"La primera sesion tipicamente incluye un proceso de admision donde tu terapeuta preguntara sobre tu historial, preocupaciones actuales y metas para la terapia. Esto les ayuda a entender tu situacion unica y como mejor apoyarte."},{"title":"Cuanto Dura","description":"La mayoria de las primeras sesiones duran entre 50-60 minutos. Esto les da a ti y a tu terapeuta suficiente tiempo para discutir tus necesidades y comenzar a establecer una conexion."},{"title":"Preguntas que Te Pueden Hacer","description":"Tu terapeuta puede preguntar sobre tu historial de salud mental, sintomas actuales, relaciones, trabajo, y que te trae a terapia. Recuerda, puedes compartir tanto o tan poco como te sientas comodo."},{"title":"Preguntas que Puedes Hacer","description":"Sientete libre de preguntar a tu terapeuta sobre su enfoque, experiencia, como se vera la terapia, o cualquier otra cosa que tengas en mente. Tus preguntas son bienvenidas e importantes."},{"title":"Discusion de Confidencialidad","description":"Tu terapeuta explicara la confidencialidad y sus limites, incluyendo cuando podrian necesitar romper la confidencialidad por razones de seguridad. Esta es una parte importante de establecer confianza y seguridad."},{"title":"Establecimiento de Metas","description":"Tu y tu terapeuta comenzaran a discutir tus metas para la terapia. Estas metas pueden evolucionar con el tiempo, y esta bien si aun no estas seguro de en que quieres trabajar."},{"title":"Papeleria y Formularios de Consentimiento","description":"Completaras la papeleria necesaria, incluyendo formularios de consentimiento y cuestionarios de admision. Estos formularios ayudan a asegurar que entiendes tus derechos y el proceso terapeutico."}],"paragraphs":[]}},{"id":"ongoing-sessions","title":"Sesiones Continuas de Terapia","icon":"ClockIcon","content":{"intro":"A medida que continuas en terapia, desarrollaras un ritmo y rutina con tu terapeuta. Esto es lo que tipicamente se ven las sesiones continuas.","items":[{"title":"Estructura Tipica de Sesion","description":"Las sesiones usualmente comienzan con un chequeo sobre como has estado desde la ultima sesion. Luego exploraras temas, trabajaras desafios, y desarrollaras insights juntos. Las sesiones terminan con un resumen y plan para el tiempo entre sesiones."},{"title":"Como Se Ve la Terapia","description":"La terapia es principalmente una conversacion, pero tambien puede incluir actividades, ejercicios, o tareas para casa. Tu terapeuta adaptara el enfoque a tus necesidades y preferencias."},{"title":"Frecuencia de Sesiones","description":"La mayoria de las personas asisten a terapia semanalmente, especialmente al principio. A medida que progresas, podrias pasar a sesiones quincenales o mensuales. La frecuencia depende de tus necesidades y metas."},{"title":"Duracion de Sesion","description":"Las sesiones estandar de terapia duran 50-60 minutos. Algunas terapias especializadas o evaluaciones pueden tener diferentes duraciones, lo cual se discutira contigo con anticipacion."},{"title":"Que Esperar con el Tiempo","description":"La terapia es un proceso. Puedes notar cambios gradualmente, y algunas sesiones pueden sentirse mas productivas que otras. El progreso no siempre es lineal, y eso es normal. Confia en el proceso y se paciente contigo mismo."},{"title":"Como Se Mide el Progreso","description":"El progreso se mide a traves de conversaciones continuas, seguimiento de metas, y tu propio sentido de mejora. Tu y tu terapeuta se comunicaran regularmente sobre como van las cosas y ajustaran segun sea necesario."},{"title":"Comunicacion Entre Sesiones","description":"Tu terapeuta te informara sobre su politica de comunicacion entre sesiones. Esto puede incluir correo electronico, llamadas telefonicas, o plataformas de mensajeria. Las situaciones de emergencia siempre se manejan de manera diferente."}],"paragraphs":[]}},{"id":"confidentiality","title":"Confidencialidad y Privacidad","icon":"LockClosedIcon","content":{"intro":"Tu privacidad y confidencialidad son fundamentales para la relacion terapeutica. Esto es lo que necesitas saber sobre como protegemos tu informacion.","items":[{"title":"Que es Confidencial","description":"Todo lo que compartes en terapia es confidencial. Esto incluye tus conversaciones, registros, y cualquier informacion sobre tu salud mental. Tu terapeuta no puede compartir esta informacion sin tu consentimiento por escrito, excepto en circunstancias especificas."},{"title":"Limites a la Confidencialidad","description":"Hay limites legales y eticos a la confidencialidad. Tu terapeuta debe romper la confidencialidad si hay riesgo de dano a ti mismo o a otros, sospecha de abuso infantil o de ancianos, o si es requerido por orden judicial. Estas situaciones se discutiran contigo cuando sea posible."},{"title":"Informacion HIPAA","description":"Cumplimos con las regulaciones HIPAA (Ley de Portabilidad y Responsabilidad del Seguro de Salud), que protegen tu informacion de salud. Tienes derechos respecto a tus registros de salud, incluyendo el derecho a acceder y solicitar enmiendas."},{"title":"Mantenimiento de Registros","description":"Tu terapeuta mantiene registros confidenciales de tus sesiones segun lo requerido por la ley y estandares profesionales. Estos registros se almacenan de forma segura y solo son accesibles para personal autorizado."},{"title":"Privacidad y Seguridad de Sesiones Virtuales","description":"Las sesiones virtuales usan plataformas seguras y encriptadas que cumplen con los requisitos HIPAA. Recomendamos usar un espacio privado y conexion a internet segura. Tu terapeuta discutira consideraciones de privacidad contigo."}],"paragraphs":[]}},{"id":"timeline-expectations","title":"Expectativas de Tiempo","icon":"ChartBarIcon","content":{"intro":"El viaje terapeutico de cada persona es unico, y no hay un cronograma unico que funcione para todos. Esto es lo que debes tener en cuenta sobre la duracion y el progreso de la terapia.","items":[{"title":"Cuanto Tiempo Puede Tomar la Terapia","description":"La duracion de la terapia varia mucho dependiendo de tus metas, los temas en los que estas trabajando, y tus necesidades individuales. Algunas personas se benefician de terapia a corto plazo (8-12 sesiones), mientras que otras participan en terapia a largo plazo. No hay un cronograma correcto o incorrecto."},{"title":"Cuando Esperar Cambios","description":"Algunas personas notan mejoras dentro de unas pocas sesiones, mientras que para otras, el cambio sucede mas gradualmente. Las primeras sesiones a menudo se enfocan en construir confianza y entender tu situacion. Se paciente contigo mismo y con el proceso."},{"title":"Compromiso y Consistencia","description":"La asistencia regular y la participacion activa son importantes para el progreso. Sin embargo, la vida sucede, y las sesiones perdidas ocasionales son comprensibles. Comunicate con tu terapeuta sobre cualquier desafio que enfrentes con la asistencia."},{"title":"Terminar la Terapia","description":"La terapia puede terminar por varias razones: has cumplido tus metas, te sientes listo para continuar independientemente, o las circunstancias cambian. Es importante tener una sesion de terminacion para procesar el final y discutir los proximos pasos. Siempre puedes regresar a terapia en el futuro si es necesario."}],"paragraphs":[]}},{"id":"virtual-vs-inperson","title":"Opciones Virtuales vs. Presenciales","icon":"ComputerDesktopIcon","content":{"intro":"Ofrecemos opciones de terapia tanto virtuales como presenciales. Ambos formatos son efectivos, y la mejor eleccion depende de tus preferencias, necesidades y circunstancias.","items":[{"title":"Diferencias y Similitudes","description":"Tanto la terapia virtual como la presencial proporcionan la misma calidad de atencion y relacion terapeutica. La terapia virtual ofrece conveniencia y accesibilidad, mientras que la terapia presencial proporciona un espacio fisico dedicado. El proceso terapeutico y la efectividad son similares en ambos formatos."},{"title":"Como Elegir","description":"Considera factores como tu nivel de comodidad, necesidades de privacidad, transporte, flexibilidad de horario, y preferencia personal. Algunas personas prefieren un formato sobre el otro, mientras que otras encuentran valor en usar ambos. Puedes discutir opciones con tu terapeuta."},{"title":"Cambiar Entre Formatos","description":"Puedes cambiar entre sesiones virtuales y presenciales segun tus necesidades. Por ejemplo, podrias preferir sesiones presenciales pero usar sesiones virtuales cuando viajas o durante mal tiempo. Discute tus preferencias con tu terapeuta."}],"paragraphs":[]}}]', '{"title":"¿Listo para Comenzar tu Viaje?","subtitle":"Da el primer paso hacia el bienestar. Estamos aqui para apoyarte en cada paso del camino.","ctas":[{"id":"schedule-session","title":"Programa tu Primera Sesion","description":"Reserva una cita que funcione para tu horario","link":"/contact/i-need-help","variant":"primary"},{"id":"learn-more","title":"Aprende Mas Sobre Nuestros Servicios","description":"Explora nuestros enfoques terapeuticos y especializaciones","link":"/services","variant":"secondary"}]}')
ON DUPLICATE KEY UPDATE meta_last_updated = VALUES(meta_last_updated), meta_version = VALUES(meta_version), seo_title = VALUES(seo_title), seo_description = VALUES(seo_description), hero_title = VALUES(hero_title), hero_subtitle = VALUES(hero_subtitle), intro_text = VALUES(intro_text), sections_json = VALUES(sections_json), cta_section_json = VALUES(cta_section_json), updated_at = NOW();
